// Flatten webhook body to root level
const body = $input.first().json.body || $input.first().json;
return [{ json: { ...body } }];

// Extraer los resultados de Outscraper y guardar contexto del webhook
const webhookData = $('Webhook').first().json;
const prepData = $('Preparar Datos').first().json;
const outscraper = $input.first().json;

let businesses = [];
if (outscraper.data && Array.isArray(outscraper.data) && outscraper.data.length > 0) {
  businesses = Array.isArray(outscraper.data[0]) ? outscraper.data[0] : outscraper.data;
}

const results = businesses.map(biz => ({
  json: {
    name: biz.name || '',
    full_address: biz.full_address || biz.address || '',
    phone: biz.phone || '',
    site: biz.site || biz.website || '',
    email_1: biz.email_1 || biz.email_2 || '',
    rating: biz.rating || 0,
    reviews: biz.reviews || 0,
    category: biz.category || biz.type || '',
    city: biz.city || prepData.city || '',
    state: biz.state || prepData.province || '',
    callback_url: prepData.callback_url,
    progress_url: prepData.progress_url,
    api_key: prepData.api_key
  }
}));

return results.length > 0 ? results : [{ json: { error: 'No results', callback_url: prepData.callback_url } }];

// =====================================================
// SCORING IA - Llama a Dify para cada negocio y combina
// los datos originales con el scoring
// =====================================================

// IMPORTANTE: Reemplaza estos valores con tus credenciales reales
const DIFY_URL = 'https://dify.optimia.disruptive-sw.com/v1/workflows/run';
const DIFY_KEY = 'TU-DIFY-APP-KEY';

const items = $input.all();
const prepData = $('Preparar Datos').first().json;

const allLeads = [];

for (let i = 0; i < items.length; i++) {
  const biz = items[i].json;

  // Si hay error de Outscraper, saltar
  if (biz.error) continue;

  const businessData = [
    `Nombre: ${biz.name || ''}`,
    `Direccion: ${biz.full_address || ''}`,
    `Telefono: ${biz.phone || ''}`,
    `Website: ${biz.site || ''}`,
    `Email: ${biz.email_1 || ''}`,
    `Rating: ${biz.rating || 0}`,
    `Reviews: ${biz.reviews || 0}`,
    `Categoria: ${biz.category || ''}`,
    `Ciudad: ${biz.city || ''}`,
    `Provincia: ${biz.state || ''}`
  ].join('\n');

  // Scoring por defecto si Dify falla
  let scoring = {
    ai_score: 50,
    quality_level: 'average',
    recommendation: 'Clasificacion automatica no disponible',
    normalized_category: biz.category || '',
    recommended_first_line: ''
  };

  try {
    const response = await fetch(DIFY_URL, {
      method: 'POST',
      headers: {
        'Authorization': `Bearer ${DIFY_KEY}`,
        'Content-Type': 'application/json'
      },
      body: JSON.stringify({
        inputs: { business_data: businessData },
        response_mode: 'blocking',
        user: 'spectra-n8n'
      })
    });

    const data = await response.json();
    const resultText = data?.data?.outputs?.result || data?.answer || '';
    const jsonMatch = resultText.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const parsed = JSON.parse(jsonMatch[0]);
      scoring.ai_score = parseInt(parsed.ai_score) || scoring.ai_score;
      scoring.quality_level = parsed.quality_level || scoring.quality_level;
      scoring.recommendation = parsed.recommendation || scoring.recommendation;
      scoring.normalized_category = parsed.normalized_category || scoring.normalized_category;
      scoring.recommended_first_line = parsed.recommended_first_line || scoring.recommended_first_line;
    }
  } catch(e) {
    // Usar scoring por defecto
  }

  allLeads.push({
    business_name: biz.name || '',
    raw_category: biz.category || '',
    normalized_category: scoring.normalized_category,
    province: biz.state || prepData.province || '',
    city: biz.city || prepData.city || '',
    website: biz.site || '',
    email: biz.email_1 || '',
    phone: biz.phone || '',
    address: biz.full_address || '',
    rating: biz.rating || 0,
    reviews_count: biz.reviews || 0,
    ai_score: scoring.ai_score,
    quality_level: scoring.quality_level,
    recommendation: scoring.recommendation,
    recommended_first_line: scoring.recommended_first_line
  });

  // Pausa de 1s entre llamadas a Dify (rate limiting)
  if (i < items.length - 1) {
    await new Promise(resolve => setTimeout(resolve, 1000));
  }
}

// Notificar progreso
try {
  if (prepData.progress_url) {
    await fetch(prepData.progress_url, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ stage: 'scoring_completed', status: 'completed', raw_count: allLeads.length })
    });
  }
} catch(e) {}

return [{
  json: {
    leads: allLeads,
    raw_count: allLeads.length,
    callback_url: prepData.callback_url,
    api_key: prepData.api_key
  }
}];
